import React, { useState } from "react";
import { registerUser } from "../api";
import OAuthButtons from "./OAuthButtons";

const RegisterForm = () => {
  const [formData, setFormData] = useState({ email: "", password: "", fullName: "", phone: "", roleName: "CLIENT" });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await registerUser(formData);
      if (res === "Регистрация прошла успешно") {
        setSuccess(res);
        setError("");
      } else {
        setError(res);
      }
    } catch (err) {
      setError("Ошибка сервера");
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h1>Регистрация</h1>
      {error && <div className="error-message">{error}</div>}
      {success && <div className="success-message">{success}</div>}

      <div className="input-box">
        <input type="text" placeholder="Полное имя" name="fullName" required value={formData.fullName} onChange={handleChange} />
        <i className="bx bxs-user"></i>
      </div>
      <div className="input-box">
        <input type="email" placeholder="Email" name="email" required value={formData.email} onChange={handleChange} />
        <i className="bx bxs-envelope"></i>
      </div>
      <div className="input-box">
        <input type="password" placeholder="Пароль" name="password" required value={formData.password} onChange={handleChange} />
        <i className="bx bxs-lock"></i>
      </div>
      <div className="input-box">
        <input type="tel" placeholder="Телефон" name="phone" required value={formData.phone} onChange={handleChange} />
        <i className="bx bxs-phone"></i>
      </div>

      <button type="submit" className="btn">Зарегистрироваться</button>
      <OAuthButtons />
    </form>
  );
};

export default RegisterForm;
